external_knowledge:
- In this metaphorical context, "lighthouses" refer to the 'sensors';
- "Beams" represent the 'observations';
- "Celestial wanderers" are the 'space objects';
- "Sky clarity" corresponds to 'data quality'.

sql:
SELECT real_name, classification
     FROM space_objects
     WHERE mean_motion < (SELECT AVG(mean_motion) FROM space_objects);

SELECT real_name
FROM space_objects
WHERE mean_motion > (
    SELECT AVG(mean_motion)
    FROM space_objects
);

SELECT norad_id, real_name, mean_motion
FROM space_objects
WHERE classification = 'debris' AND mean_motion > (
  SELECT AVG(mean_motion)
  FROM space_objects
);

SELECT real_name, classification, launch_date, decay_date
FROM space_objects
WHERE norad_id = 0;

SELECT HEX(file_id), file_path, file_size
FROM data_files
WHERE file_id = 1;

SELECT AVG(period) AS average_period
FROM space_objects
WHERE orbital_status = 'active' AND classification = 'satellite';

SELECT real_name
FROM space_objects
WHERE period = (SELECT MAX(period) FROM space_objects);

SELECT space_objects.real_name, data_files.file_path, data_files.file_size, data_files.file_type
FROM space_objects
JOIN data_files ON space_objects.norad_id = data_files.norad_id;
